import gzip,json,collections
p='/app/sgl-profile-results/1784337403.405528/1784337403.406839-TP-0.trace.json.gz'
with gzip.open(p,'rt') as f: evs=json.load(f)['traceEvents']
# Index CPU/python events by thread
threads=collections.defaultdict(list)
for e in evs:
    if e.get('ph')=='X' and 'ts' in e and 'dur' in e and e.get('cat') in ('cpu_op','python_function','cuda_runtime'):
        threads[(e.get('pid'),e.get('tid'))].append(e)
for k in threads: threads[k].sort(key=lambda e:(e['ts'], -(e.get('dur') or 0)))

def ancestors(ts, pid=2181, tid=2181, cats=None, limit=40):
    xs=[]
    for e in threads.get((pid,tid),[]):
        if e['ts'] <= ts <= e['ts']+e.get('dur',0):
            if cats is None or e.get('cat') in cats:
                xs.append(e)
    xs.sort(key=lambda e:(e.get('dur',0), e['ts']))
    return xs[:limit]

# print ancestors for DtoH hipMemcpy external IDs and for longest aten::_local_scalar_dense
for ext in [381,385,389,393,397,401,679,6729,6733,6737,6741,6745]:
    he=[e for e in evs if (e.get('args') or {}).get('External id')==ext and e.get('cat')=='cuda_runtime']
    if not he: continue
    h=he[0]
    print('\nEXT',ext,h['name'],'ts',h['ts'],'dur',h['dur'])
    for a in ancestors(h['ts'], h.get('pid'), h.get('tid'), cats=('python_function','cpu_op')):
        print(' ',a.get('cat'), a.get('name'), 'dur', round(a.get('dur',0),3), 'ext', (a.get('args') or {}).get('External id'))
# longest local scalar dense
loc=[e for e in evs if e.get('name')=='aten::_local_scalar_dense']
